1	import { Injectable, ExecutionContext } from '@nestjs/common';
2	import { ThrottlerGuard } from '@nestjs/throttler';
3	import { InjectRepository } from '@nestjs/typeorm';
4	import { Repository } from 'typeorm';
5	import { Request } from 'express';
6	import { AnomalyEvent, AnomalyEventType, AnomalyEventStatus } from '../../modules/notifications/anomaly-event.entity';
7	
8	@Injectable()
9	export class AnomalyThrottlerGuard extends ThrottlerGuard {
10	  @InjectRepository(AnomalyEvent)
11	  private readonly anomalyRepo: Repository<AnomalyEvent>;
12	
13	  /** Track by user ID when authenticated, fall back to IP. Fulfils "per user" rate limit requirement. */
14	  protected async getTracker(req: Request): Promise<string> {
15	    const user = req.user as { id?: string } | undefined;
16	    return user?.id ?? req.ip ?? req.socket?.remoteAddress ?? 'anonymous';
17	  }
18	
19	  protected async throwThrottlingException(
20	    context: ExecutionContext,
21	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
22	    throttlerLimitDetail?: any,
23	  ): Promise<void> {
24	    const req = context.switchToHttp().getRequest<Request>();
25	    const user = req.user as { id?: string } | undefined;
26	
27	    // Fire-and-forget: record anomaly event asynchronously
28	    this.anomalyRepo.save(
29	      this.anomalyRepo.create({
30	        userId: user?.id ?? null,
31	        type: AnomalyEventType.RATE_LIMIT_EXCEEDED,
32	        status: AnomalyEventStatus.PENDING,
33	        description: `Rate limit exceeded by ${user?.id ?? 'anonymous'} on ${req.method} ${req.path}`,
34	        ipAddress: (req.ip ?? req.socket?.remoteAddress ?? null),
35	        requestPath: req.path,
36	        metadata: { method: req.method, path: req.path },
37	      }),
38	    ).catch(() => { /* swallow — don't block the 429 response */ });
39	
40	    return super.throwThrottlingException(context, throttlerLimitDetail);
41	  }
42	}
