15	/**
16	 * Extract user ID from JWT token in Authorization header without full auth flow.
17	 * This allows user-scoped nonce protection even though middleware runs before guards.
18	 */
19	function extractUserIdFromToken(req: Request): string | null {
20	  const auth = req.headers['authorization'];
21	  if (!auth || !auth.startsWith('Bearer ')) return null;
22	  try {
23	    const token = auth.split(' ')[1];
24	    // Decode JWT payload (base64url) without verification — just to get the sub claim
25	    // Actual verification happens in JwtAuthGuard later
26	    const payload = JSON.parse(
27	      Buffer.from(token.split('.')[1], 'base64url').toString('utf-8'),
28	    );
29	    return payload.sub ?? payload.id ?? null;
30	  } catch {
31	    return null;
32	  }
