382	
383	    const inGroup = rule.isAbTest
384	      ? this.isUserInRolloutGroup(userId, ruleId, rule.rolloutPercentage)
385	      : true;
386	
387	    if (!inGroup) {
388	      return { inGroup: false, definition: null, version: rule.currentVersion };
389	    }
390	
391	    const version = rule.versions.find((v) => v.versionNumber === rule.currentVersion);
392	    return {
393	      inGroup: true,
394	      definition: version?.definition ?? null,
395	      version: rule.currentVersion,
396	    };
397	  }
