12	async function bootstrap() {
13	  const logger = WinstonModule.createLogger(winstonConfig);
14	
15	  // Enable HTTPS if certs are present (generated at Docker build time)
16	  const certPath = '/app/certs/selfsigned.crt';
17	  const keyPath = '/app/certs/selfsigned.key';
18	  const httpsOptions = fs.existsSync(certPath) && fs.existsSync(keyPath)
19	    ? { key: fs.readFileSync(keyPath), cert: fs.readFileSync(certPath) }
20	    : undefined;
21	
22	  const app = httpsOptions
23	    ? await NestFactory.create(AppModule, { logger, httpsOptions })
24	    : await NestFactory.create(AppModule, { logger });
25	
26	  const configService = app.get(ConfigService);
27	  const port = configService.get<number>('PORT', 4000);
28	  const corsOrigin = configService.get<string>('CORS_ORIGIN', 'https://localhost:3000');
29	
30	  // Security middleware
31	  app.use(helmet());
32	  app.use(compression());
33	
34	  // CORS — restrict to frontend origin only
35	  app.enableCors({
36	    origin: corsOrigin,
37	    credentials: true,
38	    methods: ['GET', 'POST', 'PATCH', 'DELETE', 'OPTIONS'],
39	    allowedHeaders: ['Content-Type', 'Authorization', 'X-Nonce', 'X-Timestamp'],
40	  });
41	
42	  // Global validation pipe
43	  app.useGlobalPipes(
44	    new ValidationPipe({
45	      whitelist: true,
46	      forbidNonWhitelisted: true,
47	      transform: true,
48	      transformOptions: { enableImplicitConversion: true },
49	    }),
50	  );
51	
52	  // Global exception filter
53	  app.useGlobalFilters(new AllExceptionsFilter(logger));
54	
55	  await app.listen(port);
56	  logger.log(`MeridianMed backend running on port ${port}`, 'Bootstrap');
57	}
58	
59	bootstrap();
