10	
11	  canActivate(context: ExecutionContext): boolean {
12	    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
13	      context.getHandler(),
14	      context.getClass(),
15	    ]);
16	    if (isPublic) return true;
17	
18	    const requiredRoles = this.reflector.getAllAndOverride<UserRole[]>(ROLES_KEY, [
19	      context.getHandler(),
20	      context.getClass(),
21	    ]);
22	    if (!requiredRoles || requiredRoles.length === 0) return true;
23	
24	    const { user } = context.switchToHttp().getRequest();
25	    if (!user) throw new ForbiddenException('Access denied');
26	
27	    if (!requiredRoles.includes(user.role)) {
28	      throw new ForbiddenException(`Requires one of roles: ${requiredRoles.join(', ')}`);
