5	const NONCE_WINDOW_MS = 5 * 60 * 1000; // 5 minutes
6	
7	// Paths exempt from nonce REQUIREMENT (nonce is optional but still validated if present)
8	const EXEMPT_PATHS = [
9	  '/auth/login',
10	  '/auth/refresh',
11	  '/auth/logout',
12	  '/health',
13	];
