20	    context: ExecutionContext,
21	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
22	    throttlerLimitDetail?: any,
23	  ): Promise<void> {
24	    const req = context.switchToHttp().getRequest<Request>();
25	    const user = req.user as { id?: string } | undefined;
26	
27	    // Fire-and-forget: record anomaly event asynchronously
28	    this.anomalyRepo.save(
