1	import { Injectable, NestMiddleware, BadRequestException } from '@nestjs/common';
2	import { DataSource } from 'typeorm';
3	import { Request, Response, NextFunction } from 'express';
4	
5	const NONCE_WINDOW_MS = 5 * 60 * 1000; // 5 minutes
6	
7	// Paths exempt from nonce REQUIREMENT (nonce is optional but still validated if present)
8	const EXEMPT_PATHS = [
9	  '/auth/login',
10	  '/auth/refresh',
11	  '/auth/logout',
12	  '/health',
13	];
14	
15	/**
16	 * Extract user ID from JWT token in Authorization header without full auth flow.
17	 * This allows user-scoped nonce protection even though middleware runs before guards.
18	 */
19	function extractUserIdFromToken(req: Request): string | null {
20	  const auth = req.headers['authorization'];
21	  if (!auth || !auth.startsWith('Bearer ')) return null;
22	  try {
23	    const token = auth.split(' ')[1];
24	    // Decode JWT payload (base64url) without verification — just to get the sub claim
25	    // Actual verification happens in JwtAuthGuard later
26	    const payload = JSON.parse(
27	      Buffer.from(token.split('.')[1], 'base64url').toString('utf-8'),
28	    );
29	    return payload.sub ?? payload.id ?? null;
30	  } catch {
31	    return null;
32	  }
33	}
34	
35	@Injectable()
36	export class NonceMiddleware implements NestMiddleware {
37	  constructor(private readonly dataSource: DataSource) {}
38	
39	  async use(req: Request, _res: Response, next: NextFunction) {
40	    // Only validate on sensitive write methods
41	    if (!['POST', 'PATCH', 'DELETE'].includes(req.method)) {
42	      return next();
43	    }
44	
45	    const nonce = req.headers['x-nonce'] as string;
46	    const timestamp = req.headers['x-timestamp'] as string;
47	
48	    // Check if this path is exempt from the nonce requirement
49	    const requestPath = req.baseUrl + req.path;
50	    const isExempt = EXEMPT_PATHS.some((p) => requestPath.startsWith(p));
51	
52	    // If headers are missing: exempt paths pass through, others are rejected
53	    if (!nonce || !timestamp) {
54	      if (isExempt) {
55	        return next();
56	      }
57	      throw new BadRequestException(
58	        'Missing required X-Nonce and X-Timestamp headers for write operations',
59	      );
60	    }
61	
62	    // If headers ARE present, always validate them (even on exempt paths)
63	    const ts = parseInt(timestamp, 10);
64	    const now = Date.now();
65	
66	    if (isNaN(ts) || Math.abs(now - ts) > NONCE_WINDOW_MS) {
67	      throw new BadRequestException('Request timestamp out of acceptable range (\u00b15 min)');
68	    }
69	
70	    // User-scoped nonce: extract user ID from JWT token (pre-auth phase)
71	    const userId = extractUserIdFromToken(req);
72	
73	    // Check for duplicate nonce in DB (scoped by user)
74	    try {
75	      const existing = await this.dataSource.query(
76	        `SELECT id FROM used_nonces WHERE nonce = $1 AND COALESCE(user_id, '__anon__') = COALESCE($2, '__anon__')`,
77	        [nonce, userId],
78	      );
79	
80	      if (existing.length > 0) {
81	        throw new BadRequestException('Duplicate nonce \u2014 request already processed');
82	      }
83	
84	      // Store nonce in DB
85	      await this.dataSource.query(
86	        `INSERT INTO used_nonces (nonce, user_id) VALUES ($1, $2)`,
87	        [nonce, userId],
88	      );
89	
90	      // Async cleanup of stale nonces (older than window)
91	      const cutoff = new Date(now - NONCE_WINDOW_MS).toISOString();
92	      this.dataSource.query(
93	        `DELETE FROM used_nonces WHERE created_at < $1`,
94	        [cutoff],
95	      ).catch(() => { /* non-critical cleanup */ });
96	    } catch (err) {
97	      if (err instanceof BadRequestException) throw err;
98	      // If DB is unavailable, reject to fail safe
99	      throw new BadRequestException('Nonce validation failed');
100	    }
101	
102	    next();
103	  }
104	}
