266	  async rollbackRule(id: string, userId: string): Promise<{
267	    rule: BusinessRule;
268	    restoredVersion: number;
269	    durationMs: number;
270	    completedWithinLimit: boolean;
271	  }> {
272	    const startedAt = new Date();
273	
274	    const rule = await this.ruleRepo.findOne({ where: { id }, relations: ['versions'] });
275	    if (!rule) throw new NotFoundException('Rule not found');
276	    if (rule.currentVersion <= 1) {
277	      throw new BadRequestException('Cannot rollback — no previous version exists');
278	    }
279	
280	    const targetVersion = rule.currentVersion - 1;
281	
282	    // Run rollback in a transaction for atomicity
283	    await this.dataSource.transaction(async (manager) => {
284	      // Mark current version as rolled back
285	      await manager.update(RuleVersion, { ruleId: id, versionNumber: rule.currentVersion }, {
286	        rolledBackAt: new Date(),
287	      });
288	
289	      // Restore previous version's definition as the "active" definition
290	      const prevVersion = rule.versions.find((v) => v.versionNumber === targetVersion);
291	      if (!prevVersion) {
292	        throw new BadRequestException(`Version ${targetVersion} not found`);
293	      }
294	
295	      // Update rule to point back to previous version
296	      await manager.update(BusinessRule, { id }, {
297	        currentVersion: targetVersion,
298	        status: RuleStatus.ACTIVE,
299	      });
300	    });
301	
302	    const completedAt = new Date();
303	    const durationMs = completedAt.getTime() - startedAt.getTime();
304	    const completedWithinLimit = durationMs < MAX_ROLLBACK_MS;
305	
306	    // Enforce the 5-minute rollback constraint
307	    if (!completedWithinLimit) {
308	      throw new BadRequestException(
309	        `Rollback exceeded 5-minute time limit (took ${Math.round(durationMs / 1000)}s). ` +
310	        'Rollback transaction was committed but flagged as a violation. ' +
311	        'Review and remediate manually.',
312	      );
313	    }
314	
315	    // Record rollout record for the rollback
316	    await this.rolloutRepo.save(
317	      this.rolloutRepo.create({
318	        ruleId: id,
319	        fromVersion: rule.currentVersion,
320	        toVersion: targetVersion,
321	        status: RolloutStatus.ROLLED_BACK,
322	        initiatedById: userId,
323	        startedAt,
324	        completedAt,
325	        rollbackAt: completedAt,
326	        durationMs,
327	      }),
328	    );
329	
330	    await this.auditLog.log({
331	      userId, action: 'ROLLBACK', entityType: 'BusinessRule', entityId: id,
332	      before: { version: rule.currentVersion },
333	      after: { version: targetVersion, durationMs, completedWithinLimit },
334	    });
