336	    // Reload to get updated state
337	    const updatedRule = await this.ruleRepo.findOne({ where: { id }, relations: ['versions'] });
338	    return {
339	      rule: updatedRule!,
340	      restoredVersion: targetVersion,
341	      durationMs,
342	      completedWithinLimit,
343	    };
344	  }
