355	   * Uses a simple hash-based bucketing approach for consistency.
356	   */
357	  isUserInRolloutGroup(userId: string, ruleId: string, rolloutPercentage: number): boolean {
358	    if (rolloutPercentage >= 100) return true;
359	    if (rolloutPercentage <= 0) return false;
360	    // Simple deterministic hash: sum of char codes mod 100
361	    const combined = `${userId}:${ruleId}`;
362	    let hash = 0;
363	    for (let i = 0; i < combined.length; i++) {
364	      hash = ((hash << 5) - hash + combined.charCodeAt(i)) | 0;
365	    }
366	    const bucket = Math.abs(hash) % 100;
367	    return bucket < rolloutPercentage;
368	  }
