1	import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
2	import { apiClient, tokenStorage } from '@/lib/api-client';
3	
4	export type UserRole = 'admin' | 'supervisor' | 'hr' | 'employee';
5	
6	export interface AuthUser {
7	  id: string;
8	  username: string;
9	  role: UserRole;
10	  isActive: boolean;
11	}
12	
13	interface AuthContextType {
14	  user: AuthUser | null;
15	  isAuthenticated: boolean;
16	  isLoading: boolean;
17	  login: (username: string, password: string) => Promise<void>;
18	  logout: () => Promise<void>;
19	}
20	
21	const AuthContext = createContext<AuthContextType | null>(null);
22	
23	export function AuthProvider({ children }: { children: React.ReactNode }) {
24	  const [user, setUser] = useState<AuthUser | null>(null);
25	  const [isLoading, setIsLoading] = useState(true);
26	
27	  // On mount: try to restore session using stored refresh token
28	  useEffect(() => {
29	    const restore = async () => {
30	      const { userId, refreshToken } = tokenStorage.getRefresh();
31	      if (!userId || !refreshToken) {
32	        setIsLoading(false);
33	        return;
34	      }
35	      try {
36	        const refreshRes = await apiClient.post('/auth/refresh', { userId, refreshToken });
37	        const { accessToken, refreshToken: newRefresh } = refreshRes.data.data;
38	        apiClient.defaults.headers.common['Authorization'] = `Bearer ${accessToken}`;
39	        tokenStorage.saveRefresh(userId, newRefresh);
40	
41	        const meRes = await apiClient.get('/auth/me');
42	        setUser(meRes.data.data);
43	      } catch {
44	        tokenStorage.clear();
45	      } finally {
46	        setIsLoading(false);
47	      }
48	    };
49	    restore();
50	  }, []);
51	
52	  const login = useCallback(async (username: string, password: string) => {
53	    const response = await apiClient.post('/auth/login', { username, password });
54	    const { accessToken, refreshToken, userId } = response.data.data;
55	
56	    apiClient.defaults.headers.common['Authorization'] = `Bearer ${accessToken}`;
57	    tokenStorage.saveRefresh(userId, refreshToken);
58	
59	    const meRes = await apiClient.get('/auth/me');
60	    setUser(meRes.data.data);
61	  }, []);
62	
63	  const logout = useCallback(async () => {
64	    const { userId, refreshToken } = tokenStorage.getRefresh();
65	    try {
66	      if (userId && refreshToken) {
67	        await apiClient.post('/auth/logout', { userId, refreshToken });
68	      }
69	    } catch {
70	      // ignore errors on logout
71	    } finally {
72	      setUser(null);
73	      tokenStorage.clear();
74	      delete apiClient.defaults.headers.common['Authorization'];
75	    }
76	  }, []);
77	
78	  return (
79	    <AuthContext.Provider
80	      value={{
81	        user,
82	        isAuthenticated: !!user,
83	        isLoading,
84	        login,
85	        logout,
86	      }}
87	    >
88	      {children}
89	    </AuthContext.Provider>
90	  );
91	}
92	
93	export function useAuth() {
94	  const context = useContext(AuthContext);
95	  if (!context) throw new Error('useAuth must be used within AuthProvider');
96	  return context;
97	}
