      // Create a sample with a patient identifier
      const createRes = await request(app.getHttpServer())
        .post('/lab/samples')
        .set('Authorization', `Bearer ${employeeToken}`)
        .set(nh())
        .send({
          sampleType: 'Blood',
          collectionDate: new Date().toISOString(),
          patientIdentifier: 'PATIENT-2024-SEC1',
        })
        .expect(201);

      const sampleId = createRes.body.data.id;
      // Returned identifier should be masked
      expect(createRes.body.data.patientIdentifier).toBe('****SEC1');

      // Verify DB stores it encrypted, not plaintext
      const rows = await dataSource.query(
        `SELECT patient_identifier FROM lab_samples WHERE id = $1`,
        [sampleId],
      );
      expect(rows[0].patient_identifier).not.toBe('PATIENT-2024-SEC1');
      expect(rows[0].patient_identifier).toContain(':'); // iv:hex format

      // Verify decryption works
      expect(decrypt(rows[0].patient_identifier)).toBe('PATIENT-2024-SEC1');

      // Cleanup
      await dataSource.query(`DELETE FROM lab_samples WHERE id = $1`, [sampleId]);
    });

    it('vendor sensitive fields are encrypted at rest in DB', async () => {
      // Fetch vendors from DB directly and confirm encrypted format
      const rows = await dataSource.query(
        `SELECT name, contact_name, email, phone FROM vendors LIMIT 1`,
      );
      if (rows.length > 0) {
        // All sensitive text columns should be in iv:hex format
        for (const col of ['name', 'contact_name', 'email', 'phone']) {
          expect(rows[0][col]).toContain(':');
          // Decryption should yield a non-empty string
          expect(decrypt(rows[0][col]).length).toBeGreaterThan(0);
        }
      }
    });

    it('API responses never expose raw ciphertext for encrypted fields', async () => {
      // Fetch items via API — name/description are encrypted but API returns decrypted
      const res = await request(app.getHttpServer())
        .get('/inventory/items')
        .set('Authorization', `Bearer ${adminToken}`)
        .expect(200);

      const items = res.body.data;
      if (items && items.length > 0) {
        // API response should return readable values, not iv:hex ciphertext
        const item = items[0];
        if (item.name) {
          expect(item.name).not.toMatch(/^[0-9a-f]+:[0-9a-f]+$/);
        }
      }
    });
  });"}

