1	import { Injectable, ExecutionContext } from '@nestjs/common';
2	import { ThrottlerGuard, ThrottlerGenerateKeyFunction, ThrottlerGetTrackerFunction, ThrottlerOptions } from '@nestjs/throttler';
3	import { InjectRepository } from '@nestjs/typeorm';
4	import { Repository } from 'typeorm';
5	import { Request } from 'express';
6	import { AnomalyEvent, AnomalyEventType, AnomalyEventStatus } from '../../modules/notifications/anomaly-event.entity';
7	
8	/** HTTP methods classified as sensitive (write operations). */
9	const SENSITIVE_METHODS = new Set(['POST', 'PATCH', 'PUT', 'DELETE']);
10	
11	@Injectable()
12	export class AnomalyThrottlerGuard extends ThrottlerGuard {
13	  @InjectRepository(AnomalyEvent)
14	  private readonly anomalyRepo: Repository<AnomalyEvent>;
15	
16	  /** Track by authenticated user ID when available, fall back to IP. */
17	  protected async getTracker(req: Record<string, any>): Promise<string> {
18	    const user = req.user as { id?: string } | undefined;
19	    return user?.id ?? req.ip ?? req.socket?.remoteAddress ?? 'anonymous';
20	  }
21	
22	  /**
23	   * Override handleRequest to enforce the "sensitive" throttler only on
24	   * authenticated write operations. Non-sensitive requests skip the
25	   * "sensitive" bucket entirely, so GET requests are unaffected.
26	   */
27	  protected async handleRequest(
28	    context: ExecutionContext,
29	    limit: number,
30	    ttl: number,
31	    throttler: ThrottlerOptions,
32	    getTracker: ThrottlerGetTrackerFunction,
33	    generateKey: ThrottlerGenerateKeyFunction,
34	  ): Promise<boolean> {
35	    const req = context.switchToHttp().getRequest<Request>();
36	    const isSensitiveMethod = SENSITIVE_METHODS.has(req.method);
37	    const isAuthenticated = !!(req.user as { id?: string } | undefined)?.id;
38	
39	    // For the "sensitive" named throttler: only enforce on authenticated write ops
40	    if (throttler.name === 'sensitive') {
41	      if (!isSensitiveMethod || !isAuthenticated) {
42	        return true; // skip — not a sensitive action
43	      }
44	    }
45	
46	    return super.handleRequest(context, limit, ttl, throttler, getTracker, generateKey);
47	  }
48	
49	  protected async throwThrottlingException(
50	    context: ExecutionContext,
51	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
52	    throttlerLimitDetail?: any,
53	  ): Promise<void> {
54	    const req = context.switchToHttp().getRequest<Request>();
55	    const user = req.user as { id?: string } | undefined;
56	
57	    // Fire-and-forget: record anomaly event asynchronously
58	    this.anomalyRepo.save(
59	      this.anomalyRepo.create({
60	        userId: user?.id ?? null,
61	        type: AnomalyEventType.RATE_LIMIT_EXCEEDED,
62	        status: AnomalyEventStatus.PENDING,
63	        description: `Rate limit exceeded by ${user?.id ?? 'anonymous'} on ${req.method} ${req.path}`,
64	        ipAddress: (req.ip ?? req.socket?.remoteAddress ?? null),
65	        requestPath: req.path,
66	        metadata: { method: req.method, path: req.path },
67	      }),
68	    ).catch(() => { /* swallow — don't block the 429 response */ });
69	
70	    return super.throwThrottlingException(context, throttlerLimitDetail);
71	  }
72	}
