3	const ALGORITHM = 'aes-256-cbc';
4	const IV_LENGTH = 16;
5	const KEY_LENGTH = 32;
6	
7	function getKey(): Buffer {
8	  const raw = process.env.ENCRYPTION_KEY;
9	  if (!raw || raw.length < 16) {
10	    throw new Error(
11	      'ENCRYPTION_KEY environment variable is required and must be at least 16 characters. ' +
12	      'Set it in docker-compose.yml or your environment before starting the application.',
13	    );
14	  }
15	  // Derive a 32-byte key deterministically from the env var
16	  return crypto.createHash('sha256').update(raw).digest().slice(0, KEY_LENGTH);
17	}
18	
19	export function encrypt(plaintext: string): string {
20	  const iv = crypto.randomBytes(IV_LENGTH);
21	  const cipher = crypto.createCipheriv(ALGORITHM, getKey(), iv);
22	  const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
23	  return iv.toString('hex') + ':' + encrypted.toString('hex');
24	}
25	
26	export function decrypt(ciphertext: string): string {
27	  const [ivHex, encHex] = ciphertext.split(':');
28	  if (!ivHex || !encHex) throw new Error('Invalid ciphertext format');
29	  const iv = Buffer.from(ivHex, 'hex');
30	  const encrypted = Buffer.from(encHex, 'hex');
31	  const decipher = crypto.createDecipheriv(ALGORITHM, getKey(), iv);
32	  const decrypted = Buffer.concat([decipher.update(encrypted), decipher.final()]);
33	  return decrypted.toString('utf8');
34	}
