1	import {
2	  Injectable,
3	  UnauthorizedException,
4	  ForbiddenException,
5	} from '@nestjs/common';
6	import { JwtService } from '@nestjs/jwt';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository } from 'typeorm';
9	import * as bcrypt from 'bcryptjs';
10	import { randomBytes, createHash } from 'crypto';
11	import { ConfigService } from '@nestjs/config';
12	import { User } from '../users/user.entity';
13	import { RefreshToken } from './refresh-token.entity';
14	import { LoginDto } from './dto/login.dto';
15	
16	@Injectable()
17	export class AuthService {
18	  private readonly refreshExpiresMs: number;
19	
20	  constructor(
21	    @InjectRepository(User) private readonly userRepo: Repository<User>,
22	    @InjectRepository(RefreshToken) private readonly tokenRepo: Repository<RefreshToken>,
23	    private readonly jwtService: JwtService,
24	    private readonly configService: ConfigService,
25	  ) {
26	    // Parse "8h" → milliseconds
27	    const raw = configService.get<string>('REFRESH_TOKEN_EXPIRES_IN', '8h');
28	    this.refreshExpiresMs = this.parseExpiry(raw);
29	  }
30	
31	  async login(dto: LoginDto, ip?: string) {
32	    const user = await this.userRepo.findOne({
33	      where: { username: dto.username },
34	    });
35	
36	    if (!user) throw new UnauthorizedException('Invalid credentials');
37	    if (!user.isActive) throw new ForbiddenException('Account is inactive');
38	
39	    const valid = await bcrypt.compare(dto.password, user.passwordHash);
40	    if (!valid) throw new UnauthorizedException('Invalid credentials');
41	
42	    await this.userRepo.update(user.id, { lastLoginAt: new Date() });
43	
44	    const accessToken = this.issueAccessToken(user);
45	    const { refreshToken, tokenRecord } = await this.issueRefreshToken(user);
46	
47	    return {
48	      accessToken,
49	      refreshToken,
50	      userId: user.id,
51	      expiresIn: 900, // 15 min in seconds
52	    };
53	  }
54	
55	  async refresh(userId: string, rawToken: string) {
56	    const hash = this.hashToken(rawToken);
57	
58	    const record = await this.tokenRepo.findOne({
59	      where: { userId, tokenHash: hash },
60	    });
61	
62	    if (!record || record.revokedAt || record.expiresAt < new Date()) {
63	      // Possible token reuse — revoke all tokens for user (detect theft)
64	      if (record && !record.revokedAt) {
65	        await this.tokenRepo.update({ userId }, { revokedAt: new Date() });
66	      }
67	      throw new UnauthorizedException('Invalid or expired refresh token');
68	    }
69	
70	    const user = await this.userRepo.findOne({
71	      where: { id: userId, isActive: true },
72	    });
73	    if (!user) throw new UnauthorizedException('User not found or inactive');
74	
75	    // Rotate: revoke old, issue new
76	    await this.tokenRepo.update(record.id, { revokedAt: new Date() });
77	
78	    const accessToken = this.issueAccessToken(user);
79	    const { refreshToken } = await this.issueRefreshToken(user);
80	
81	    return { accessToken, refreshToken, userId: user.id, expiresIn: 900 };
82	  }
83	
84	  async logout(userId: string, rawToken: string) {
85	    const hash = this.hashToken(rawToken);
86	    await this.tokenRepo.update({ userId, tokenHash: hash }, { revokedAt: new Date() });
87	  }
88	
89	  async getProfile(userId: string) {
90	    const user = await this.userRepo.findOne({ where: { id: userId } });
91	    if (!user) throw new UnauthorizedException('User not found');
92	    const { passwordHash: _, ...profile } = user;
93	    return profile;
94	  }
95	
96	  // ── Helpers ────────────────────────────────────────────────────────────
97	
98	  private issueAccessToken(user: User): string {
99	    return this.jwtService.sign({
100	      sub: user.id,
101	      username: user.username,
102	      role: user.role,
103	    });
104	  }
105	
106	  private async issueRefreshToken(user: User): Promise<{ refreshToken: string; tokenRecord: RefreshToken }> {
107	    const rawToken = randomBytes(40).toString('hex');
108	    const tokenHash = this.hashToken(rawToken);
109	    const expiresAt = new Date(Date.now() + this.refreshExpiresMs);
110	
111	    const tokenRecord = this.tokenRepo.create({ userId: user.id, tokenHash, expiresAt });
112	    await this.tokenRepo.save(tokenRecord);
113	
114	    return { refreshToken: rawToken, tokenRecord };
115	  }
116	
117	  private hashToken(raw: string): string {
118	    return createHash('sha256').update(raw).digest('hex');
119	  }
120	
121	  private parseExpiry(expiry: string): number {
122	    const unit = expiry.slice(-1);
123	    const value = parseInt(expiry.slice(0, -1), 10);
124	    switch (unit) {
125	      case 'h': return value * 60 * 60 * 1000;
126	      case 'm': return value * 60 * 1000;
127	      case 'd': return value * 24 * 60 * 60 * 1000;
128	      default: return 8 * 60 * 60 * 1000;
129	    }
130	  }
131	}
