81	 * Serialises the object to JSON, encrypts the string, and stores as text.
82	 * On read, decrypts and parses back to an object.
83	 */
84	export const jsonAesTransformer = {
85	  to(value: Record<string, unknown> | null | undefined): string | null {
86	    if (value == null) return null;
87	    return encrypt(JSON.stringify(value));
88	  },
89	  from(value: string | null | undefined): Record<string, unknown> | null {
90	    if (value == null || value === '') return null;
91	    try {
92	      const json = decrypt(value);
93	      return JSON.parse(json);
94	    } catch {
95	      // Fallback for unencrypted legacy JSONB data
96	      if (typeof value === 'object') return value as Record<string, unknown>;
97	      try { return JSON.parse(value); } catch { return null; }
98	    }
99	  },
100	};
