102	export const aesTransformer = {
103	  to(value: string | null | undefined): string | null {
104	    if (value == null || value === '') return null;
105	    return encrypt(value);
106	  },
107	  from(value: string | null | undefined): string | null {
108	    if (value == null || value === '') return null;
109	    try {
110	      return decrypt(value);
111	    } catch {
112	      // Return raw value if decryption fails (e.g., unencrypted legacy data)
113	      return value ?? null;
114	    }
